namespace BgControls.Windows.Input.Touch;/// <summary>/// 滑动事件处理程序委托./// </summary>/// <param name="sender">事件发送者.</param>/// <param name="args">滑动事件参数.</param>public delegate void SwipeEventHandler(object sender, SwipeEventArgs args);/// <summary>/// 滑动事件参数类，包含滑动的位移信息./// </summary>public class SwipeEventArgs : TouchEventArgs{    /// <summary>    /// Initializes a new instance of the <see cref="SwipeEventArgs"/> class.    /// </summary>    /// <param name="routedEvent">路由事件标识.</param>    /// <param name="originalTouchArgs">原始触控事件参数.</param>    /// <param name="horizontalDelta">水平位移量.</param>    /// <param name="verticalDelta">垂直位移量.</param>    internal SwipeEventArgs(RoutedEvent routedEvent, TouchEventArgs originalTouchArgs, double horizontalDelta, double verticalDelta)        : base(routedEvent, originalTouchArgs)    {        // 将水平和垂直位移量赋值给只读属性.        this.HorizontalChange = horizontalDelta;        this.VerticalChange = verticalDelta;    }    /// <summary>    /// Gets 水平位移量.    /// </summary>    public double HorizontalChange { get; }    /// <summary>    /// Gets 垂直位移量.    /// </summary>    public double VerticalChange { get; }}